.darma-loader-darma-custom-068 {
  --s: 40px;
  --g: 5px;  

  height: calc(2*(var(--s) + var(--g)));
  aspect-ratio: 1;
  background:
    radial-gradient(calc(var(--s)/sqrt(2)) at calc(50% - .1*var(--s)) calc(50% - .2*var(--s)),#0000 5%,60%,var(--loader-secondary-color, #111) 98%), 
    linear-gradient(var(--loader-color, #fe4365) 0 0) no-repeat #fff; 
  background-size: 50% 50%;
  mask: radial-gradient(calc(var(--s)/2),#000 calc(100% - 1px),#0000) 0 0/50% 50%;
  animation: darma-loader-darma-custom-068-l12 steps(3) 1.5s infinite;
}
@keyframes darma-loader-darma-custom-068-l12 {
  0%,12.5%    {background-position:0 0}
  12.6%,37.5% {background-position:0 0,100% 0}
  37.6%,62.5% {background-position:0 0,100% 100%}
  62.6%,87.5% {background-position:0 0,0 100%}
  87.6%,100%  {background-position:0 0}
}

